package pe.edu.utp.tmo.infrastructure.persistence; import java.util.Optional; import org.springframework.stereotype.Repository; import pe.edu.utp.tmo.dao.UsuarioDAO; import pe.edu.utp.tmo.infrastructure.persistence.repository.UsuarioRepository; import pe.edu.utp.tmo.model.entity.Usuario; @Repository public class UsuarioJpaDAO implements UsuarioDAO{ private final UsuarioRepository r; public UsuarioJpaDAO(UsuarioRepository r){this.r=r;} public Optional<Usuario> buscarPorCorreo(String c){return r.findByCorreoIgnoreCase(c);} public boolean existePorCorreo(String c){return r.existsByCorreoIgnoreCase(c);} public Usuario guardar(Usuario u){return r.save(u);} public Optional<Usuario> buscarPorId(Long id){return r.findById(id);} }